        let target = nums[i] * k;
        let mut low = i;
        let mut high = n - 1;
        let mut best = i - 1;
        while low <= high {
            let mid = (low + high) / 2;
            if nums[mid] <= target {
                best = mid;
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }
        let current_window = best - i + 1;
        if current_window > max_window {
            max_window = current_window;
        }
    }
    (n as i64) - max_window as i64
}
